1	import React, { useEffect, useState } from 'react';
2	import axios from 'axios';
3	import Sidebar from '../components/Sidebar';
4	import '../css/Dashboard.css';
5	import '../css/Management.css';
6	
7	const REVIEW_STATUSES = ['Pending Review', 'False Positive', 'Escalated', 'Resolved'];
8	
9	// FM-only manual review queue for suspicious / critical access logs produced
10	// automatically by the V-Patrol facial-recognition engine.
11	const SecurityReview = () => {
12	  const [logs, setLogs] = useState([]);
13	  const [loading, setLoading] = useState(true);
14	  const [filter, setFilter] = useState('Pending Review');
15	  const [drafts, setDrafts] = useState({}); // { [logId]: { reviewStatus, reviewNotes } }
16	  const [savingId, setSavingId] = useState(null);
17	  const [notification, setNotification] = useState('');
18	
19	  const token = localStorage.getItem('accessToken');
20	
21	  const fetchLogs = async (statusFilter) => {
22	    setLoading(true);
23	    try {
24	      const query = statusFilter === 'All' ? '?limit=100' : `?status=${encodeURIComponent(statusFilter)}&limit=100`;
25	      const res = await axios.get(`/api/security/logs${query}`, {
26	        headers: { Authorization: `Bearer ${token}` }
27	      });
28	      setLogs(Array.isArray(res.data) ? res.data : []);
29	    } catch (err) {
30	      console.error('Failed to load security logs:', err);
31	      setLogs([]);
32	    } finally {
33	      setLoading(false);
34	    }
35	  };
36	
37	  useEffect(() => {
38	    fetchLogs(filter);
39	  }, [filter]);
40	
41	  useEffect(() => {
42	    if (!notification) return;
43	    const timer = setTimeout(() => setNotification(''), 4000);
44	    return () => clearTimeout(timer);
45	  }, [notification]);
46	
47	  const setDraft = (logId, field, value) => {
48	    setDrafts(prev => ({
49	      ...prev,
50	      [logId]: { ...prev[logId], [field]: value }
51	    }));
52	  };
53	
54	  const saveReview = async (log) => {
55	    const draft = drafts[log.id] || {};
56	    const reviewStatus = draft.reviewStatus || log.reviewStatus || 'Pending Review';
57	    const reviewNotes = draft.reviewNotes ?? log.reviewNotes ?? '';
58	
59	    setSavingId(log.id);
60	    try {
61	      await axios.patch(`/api/security/logs/${log.id}/review`,
62	        { reviewStatus, reviewNotes },
63	        { headers: { Authorization: `Bearer ${token}` } }
64	      );
65	      setNotification(`Log #${String(log.id).slice(0, 8)} marked "${reviewStatus}".`);
66	      fetchLogs(filter);
67	    } catch (err) {
68	      console.error('Failed to save review:', err);
69	      setNotification('Could not save review. Please try again.');
70	    } finally {
71	      setSavingId(null);
72	    }
73	  };
74	
75	  const badgeClass = (status) => {
76	    if (status === 'Resolved' || status === 'False Positive') return 'status-badge active';
77	    return 'status-badge inactive';
78	  };
79	
80	  return (
81	    <div className="dashboard-layout">
