file.content:
/* --- Desktop Layout (Full-Width / Stretched) --- */
.users-container {
    width: 100%;
    margin: 0;
    padding: 0; 
}

/* Tighten the gap between the Title and the Table */
.dashboard-header {
    margin-bottom: 1rem !important; 
    width: 100%;
}

.self-enroll-btn {
    background: linear-gradient(135deg, #2563eb, #0891b2);
    color: white;
    border: 1px solid rgba(147, 197, 253, 0.35);
    padding: 12px 18px;
    border-radius: 8px;
    font-weight: 800;
    cursor: pointer;
    box-shadow: 0 10px 24px rgba(37, 99, 235, 0.25);
    white-space: nowrap;
}

.self-enroll-btn:hover {
    transform: translateY(-1px);
    box-shadow: 0 14px 30px rgba(37, 99, 235, 0.35);
}

.add-user-btn {
    background-color: #3b82f6;
    color: white;
    border: none;
    padding: 10px 20px;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.2s;
}

.add-user-btn:hover {
    background-color: #2563eb;
}

/* --- Table Wrapper (The Main Card) --- */
.table-wrapper {
    background-color: #1e293b;
    border: 1px solid #334155;
    border-radius: 12px;
    overflow-x: hidden; 
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
    width: 100%;
}

/* --- Dark Mode Table Styling --- */
.users-table {
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
    text-align: left;
    color: #f8fafc;
}

.users-table th:nth-child(1),
.users-table td:nth-child(1) {
    width: 22%;
}

.users-table th:nth-child(2),
.users-table td:nth-child(2) {
    width: 16%;
}

.users-table th:nth-child(3),
.users-table td:nth-child(3) {
    width: 20%;
}

.users-table th:nth-child(4),
.users-table td:nth-child(4) {
    width: 13%;
}

.users-table th:nth-child(5),
.users-table td:nth-child(5) {
    width: 10%;
}

.users-table th:nth-child(6),
.users-table td:nth-child(6) {
    width: 19%;
}

.users-table th {
    background-color: rgba(15, 23, 42, 0.4);
    padding: 18px 24px;
    font-size: 0.75rem;
    text-transform: uppercase;
    color: #94a3b8;
    font-weight: 700;
    letter-spacing: 0.1em;
    border-bottom: 1px solid #334155;
}

/* --- UPDATED: Aligns "ACTIONS" header to the center --- */
.users-table th:last-child {
    text-align: center;
}

.users-table td {
    padding: 18px 24px;
    border-bottom: 1px solid #334155;
    font-size: 0.95rem;
    vertical-align: middle; 
}

.users-table tbody tr:hover {
    background-color: rgba(51, 65, 85, 0.3); 
}

/* --- User Info Section --- */
.user-name-cell {
    font-weight: 700;
}

.user-identity {
    display: flex;
    align-items: center;
    gap: 10px;
    min-width: 0;
}

.user-avatar-small {
    width: 30px;
    height: 30px;
    background: linear-gradient(135deg, #6366f1, #3b82f6);
    border-radius: 50%;
    display: flex;
    justify-content: center;
    align-items: center;
    font-weight: bold;
    font-size: 0.8rem;
    color: white;
    flex-shrink: 0;
}

.user-name-text {
    display: inline-flex;
    align-items: baseline;
    min-width: 0;
    white-space: nowrap;
}

/* --- Presence Status Tags --- */
.presence-tag {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 6px 14px;
    border-radius: 8px;
    font-size: 0.85rem;
    font-weight: 600;
}

.presence-tag.on-site {
    background: rgba(16, 185, 129, 0.1);
    color: #10b981;
    border: 1px solid rgba(16, 185, 129, 0.2);
}

.presence-tag.off-site {
    background: rgba(148, 163, 184, 0.1);
    color: #94a3b8;
    border: 1px solid rgba(148, 163, 184, 0.2);
}

/* --- Role Badges --- */
.role-badge {
    padding: 4px 10px;
    border-radius: 6px;
    font-size: 0.7rem;
    font-weight: 800;
    text-transform: uppercase;
}

.role-fm { background: rgba(59, 130, 246, 0.15); color: #60a5fa; border: 1px solid rgba(59, 130, 246, 0.3); }
.role-tenant { background: rgba(245, 158, 11, 0.15); color: #fbbf24; border: 1px solid rgba(245, 158, 11, 0.3); }
.role-staff { background: rgba(139, 92, 246, 0.15); color: #a78bfa; border: 1px solid rgba(139, 92, 246, 0.3); }

/* --- ACTIONS COLUMN ALIGNMENT --- */
.actions-cell {
    text-align: center;
}

.action-btn {
    border: 1px solid transparent;
    font-weight: 600;
    font-size: 0.76rem;
    cursor: pointer;
    white-space: nowrap;
    border-radius: 8px;
    padding: 9px 10px;
    background: rgba(15, 23, 42, 0.45);
    line-height: 1.1;
    min-width: 88px;
    transition: all 0.18s ease;
}

.action-button-group {
    display: grid;
    grid-template-columns: repeat(2, minmax(88px, 1fr));
    gap: 8px;
    max-width: 210px;
    margin: 0 auto;
}

.action-neutral { 
    color: #60a5fa; 
    border-color: rgba(96, 165, 250, 0.18);
}

.action-neutral:hover,
.action-bio:hover {
    background: rgba(37, 99, 235, 0.22);
    border-color: rgba(96, 165, 250, 0.45);
}

.action-warning {
    color: #fda4af;
    border-color: rgba(244, 63, 94, 0.28);
    background: rgba(244, 63, 94, 0.08);
}

.action-warning:hover {
    background: rgba(244, 63, 94, 0.18);
    border-color: rgba(244, 63, 94, 0.5);
}

.action-restore {
    color: #34d399;
    border-color: rgba(16, 185, 129, 0.3);
    background: rgba(16, 185, 129, 0.08);
}

.action-restore:hover {
    background: rgba(16, 185, 129, 0.18);
    border-color: rgba(16, 185, 129, 0.5);
}

.action-bio {
    color: #38bdf8;
    border-color: rgba(56, 189, 248, 0.2);
}

.action-danger {
    color: #fb7185;
    border-color: rgba(251, 113, 133, 0.2);
}

.action-danger:hover {
    background: rgba(220, 38, 38, 0.2);
    border-color: rgba(251, 113, 133, 0.5);
}

.disabled-action,
.disabled-action:hover {
    color: #475569;
    border-color: rgba(71, 85, 105, 0.22);
    background: rgba(15, 23, 42, 0.35);
    cursor: not-allowed;
    opacity: 0.5;
}

.delete-variant {
    border-color: rgba(251, 113, 133, 0.45);
}

.delete-btn {
    background: #dc2626;
}

.delete-btn:hover {
    background: #b91c1c;
    transform: translateY(-2px);
}

.users-toast {
    position: fixed;
    top: 24px;
    right: 24px;
    z-index: 2500;
    background: #102033;
    color: #c7f9df;
    border-left: 4px solid #10b981;
    border-radius: 10px;
    padding: 14px 18px;
    box-shadow: 0 18px 40px rgba(0, 0, 0, 0.35);
    font-weight: 700;
}

/* =========================================
   MOBILE RESPONSIVENESS
   ========================================= */
@media (max-width: 768px) {
    .users-table tr {
        margin-bottom: 20px;
        border: 1px solid #334155;
        border-radius: 12px;
        background-color: #1e293b;
        padding: 15px;
        display: block;
    }

    .users-table thead { display: none; }
    .users-table td { 
        display: flex; 
        justify-content: space-between; 
        padding: 10px 5px;
        border: none;
    }

    .actions-cell {
        justify-content: center; /* Keep centered on mobile too */
        padding-top: 15px !important;
    }

    .user-name-cell {
        border-bottom: 1px solid #334155 !important;
        padding-bottom: 15px !important;
        justify-content: flex-start !important;
    }

    .user-identity {
        justify-content: flex-end;
    }
}

.row-suspended {
    opacity: 0.6;
    filter: grayscale(0.5);
}

.row-suspended .presence-tag {
    background: #0f172a !important;
    color: #475569 !important;
    border-color: transparent !important;
}

/* Modal Overlay */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(2, 6, 17, 0.85); 
    backdrop-filter: blur(4px); 
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 2000;
    animation: fadeIn 0.2s ease-out;
}

/* Modal Content Box */
.security-modal {
    background: #1e293b;
    border: 1px solid #334155;
    border-radius: 16px;
    padding: 30px;
    width: 100%;
    max-width: 450px;
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
    text-align: center;
    animation: scaleUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.modal-header {
    margin-bottom: 20px;
}

.modal-icon {
    font-size: 2.5rem;
    display: block;
    margin-bottom: 10px;
}

.security-modal h3 {
    color: #f8fafc;
    font-size: 1.25rem;
    font-weight: 700;
}

.security-modal p {
    color: #94a3b8;
    line-height: 1.6;
    margin-bottom: 30px;
}

/* Modal Buttons */
.modal-actions {
    display: flex;
    gap: 12px;
    justify-content: center;
}

.cancel-btn {
    background: #334155;
    color: #cbd5e1;
    border: none;
    padding: 12px 24px;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
}

.confirm-btn {
    border: none;
    padding: 12px 24px;
    border-radius: 8px;
    font-weight: 600;
    color: white;
    cursor: pointer;
    transition: all 0.2s;
}

.suspend-btn {
    background: #f43f5e;
}

.reactivate-btn {
    background: #10b981;
}

.cancel-btn:hover { background: #475569; }
.suspend-btn:hover { background: #e11d48; transform: translateY(-2px); }
.reactivate-btn:hover { background: #059669; transform: translateY(-2px); }

/* Animations */
@keyframes scaleUp {
    from { transform: scale(0.9); opacity: 0; }
    to { transform: scale(1); opacity: 1; }
}

@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

.self-tag {
    font-size: 0.75rem;
    color: #64748b;
    font-weight: 400;
    margin-left: 4px;
    font-style: italic;
}

/* =========================================
   LAPTOP RESPONSIVENESS (1366px and below)
   ========================================= */
@media (max-width: 1366px) and (min-width: 769px) {
    .users-table th,
    .users-table td {
        padding: 14px 12px;
        font-size: 0.85rem; 
    }

    /* 🎯 THE MAGIC FIX: Forces badges, dates, and buttons to stay on one straight line */
    .user-name-text,
    .role-badge,
    .presence-tag,
    .time-cell,
    .actions-cell {
        white-space: nowrap;
    }

    .user-avatar-small {
        width: 28px;
        height: 28px;
        font-size: 0.75rem;
    }

    .presence-tag {
        padding: 5px 12px;
        font-size: 0.75rem;
    }

    .action-btn {
        font-size: 0.8rem;
    }

    .action-button-group {
        max-width: 200px;
    }

    .action-btn {
        min-width: 82px;
        padding: 8px 9px;
        font-size: 0.74rem;
    }
}

