.sidebar-bottom {
  padding: 20px;
  border-top: 1px solid #232a3d;
}

.user-profile {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 15px;
}

.user-avatar {
  font-size: 1.5rem;
  background: #0b0f1a;
  padding: 8px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;

